import json
import re

# Load books info
try:
    with open(locals()['var_function-call-10420788293867656136'], 'r') as f:
        books_info = json.load(f)
except Exception as e:
    books_info = []

# Load reviews
try:
    with open(locals()['var_function-call-16589839961701176166'], 'r') as f:
        reviews = json.load(f)
except Exception as e:
    reviews = []

# Helper to extract ID number
def get_id_num(s, prefix):
    if s and s.startswith(prefix):
        return s[len(prefix):]
    return None

# Parse books to get year
# Regex for date: look for year 19xx or 20xx in details
year_pattern = re.compile(r'\b(19\d{2}|20\d{2})\b')

book_years = {}
debug_year_parsing = []

for book in books_info:
    bid_str = book.get('book_id')
    details = book.get('details', '')
    bid = get_id_num(bid_str, 'bookid_')

    if bid:
        # Find all candidate years
        matches = [int(m.group()) for m in year_pattern.finditer(details)]
        year = None

        # Heuristic: Prefer year after "published" or "released" or "edition"
        # Find index of keywords
        idx = -1
        for kw in ["published", "released", "edition"]:
            idx = details.lower().find(kw)
            if idx != -1:
                break

        if idx != -1:
            # Find closest year after idx
            candidates = [y for m in year_pattern.finditer(details) if m.start() >= idx for y in [int(m.group())]]
            if candidates:
                # Filter valid years (e.g. <= 2024)
                valid = [y for y in candidates if 1900 <= y <= 2024]
                if valid:
                    year = valid[0]

        if not year and matches:
             # Fallback
             valid = [y for y in matches if 1900 <= y <= 2024]
             if valid:
                 year = valid[0]

        if year:
            book_years[bid] = year

        if len(debug_year_parsing) < 3:
            debug_year_parsing.append({'bid': bid, 'details': details[:50], 'matches': matches, 'year': year})

# Aggregate reviews
book_ratings = {}
for r in reviews:
    pid_str = r.get('purchase_id')
    rating = r.get('rating')
    pid = get_id_num(pid_str, 'purchaseid_')

    if pid and rating:
        try:
            r_val = float(rating)
            if pid not in book_ratings:
                book_ratings[pid] = []
            book_ratings[pid].append(r_val)
        except:
            pass

# Join and Group by Decade
decade_stats = {} # decade_str -> {'books': set(), 'all_ratings': []}

for bid, year in book_years.items():
    if bid in book_ratings:
        decade = (year // 10) * 10
        decade_str = f"{decade}s"

        if decade_str not in decade_stats:
            decade_stats[decade_str] = {'books': set(), 'all_ratings': []}

        decade_stats[decade_str]['books'].add(bid)
        decade_stats[decade_str]['all_ratings'].extend(book_ratings[bid])

# Filter and find max
final_results = []
for dec, stats in decade_stats.items():
    num_books = len(stats['books'])
    if num_books >= 10:
        avg_rating = sum(stats['all_ratings']) / len(stats['all_ratings'])
        final_results.append({
            'decade': dec,
            'avg_rating': avg_rating,
            'num_books': num_books
        })

final_results.sort(key=lambda x: x['avg_rating'], reverse=True)

# Output
if not final_results:
    # Debug output if empty
    debug_info = {
        'num_books_parsed': len(book_years),
        'num_books_rated': len(book_ratings),
        'intersection': len(set(book_years.keys()) & set(book_ratings.keys())),
        'decades_found': list(decade_stats.keys()),
        'sample_years': debug_year_parsing
    }
    print("__RESULT__:")
    print(json.dumps(debug_info))
else:
    print("__RESULT__:")
    print(json.dumps(final_results))

